const text = $json.data || "";

// split lines
const lines = text.split("\n");

// regex patterns
const emailRegex = /\b[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}\b/i;
const phoneRegex = /\b\d{3}-\d{3}-\d{4}\b/i;
const nameRegex = /^[A-Z][a-z]+\s[A-Z][a-z]+$/;
const companyRegex = /^[A-Za-z&\s]+$/;

let contactEmail = "";
let partnerEmail = "";
let phone = "";
let contactName = "";
let partnerCompany = "";

for (const line of lines) {

  // extract message after "From BP :"
  const match = line.match(/From BP\s*:\s*(.*)/);
  if (!match) continue;

  const value = match[1].trim();

  // classify values
  if (emailRegex.test(value)) {

    if (!contactEmail) {
      contactEmail = value;
    } else {
      partnerEmail = value;
    }

  } else if (phoneRegex.test(value)) {

    phone = value;

  } else if (nameRegex.test(value)) {

    contactName = value;

  } else if (companyRegex.test(value) && value.length > 3) {

    partnerCompany = value;

  }

}

return [{
  json: {
    onboarding: {
      contact_name: contactName,
      contact_email: contactEmail,
      phone: phone,
      partner_company: partnerCompany,
      partner_email: partnerEmail
    }
  }
}];

// get v1 memo
const memo = $json.memo[0];

// get onboarding data from previous node
const onboarding = $items("Code in JavaScript")[0].json.onboarding;

const changes = [];

// ensure routing object exists
if (!memo.emergency_routing_rules) {
  memo.emergency_routing_rules = {};
}

// update primary contact
if (onboarding.contact_name) {
  memo.emergency_routing_rules.primary_contact = onboarding.contact_name;
  changes.push(`Primary contact added: ${onboarding.contact_name}`);
}

// update email
if (onboarding.contact_email) {
  memo.contact_email = onboarding.contact_email;
  changes.push("Business contact email added");
}

// update phone
if (onboarding.phone) {
  memo.phone = onboarding.phone;
  changes.push("Business phone number added");
}

// ensure integrations array exists
if (!memo.integration_constraints) {
  memo.integration_constraints = [];
}

// add referral partner
if (onboarding.partner_company) {
  memo.integration_constraints.push(`Referral partner: ${onboarding.partner_company}`);
  changes.push(`Referral partner added: ${onboarding.partner_company}`);
}

// upgrade version
memo.version = "v2";
memo.notes = "Updated from onboarding call dataset";

return [{
  json: {
    memo: memo,
    changelog: changes
  }
}];

const memo = $json.memo;

const config = {
  account_id: memo.account_id,
  company_name: memo.company_name,

  model: "retell",

  voice: "professional_female",

  routing: {
    emergency_contact: memo.emergency_routing_rules?.primary_contact || "",
    fallback_action: memo.after_hours_flow_summary || ""
  },

  services: memo.services_supported || [],

  integrations: memo.integration_constraints || []
};

return [{
  json: config
}];
